+  errValue: E,
+  maybeItems?: Iterable<Maybe<T>>
+): Result<T[], E> | ((items: Iterable<Maybe<T>>) => Result<T[], E>) {
+  const op = (items: Iterable<Maybe<T>>): Result<T[], E> => {
+    const values: T[] = [];
+    for (const item of items) {
+      if (item.isNothing) return Result.err<T[], E>(errValue);
+      values.push(item.value);
+    }
